import json
from datetime import datetime

# Load case data from stored results
case_result_key = "var_functions.query_db:2"
account_result_key = "var_functions.query_db:16"

# Debug: let's see what's in the locals
current_locals = dict(locals())
for key in current_locals:
    if 'query_db' in str(key):
        print("Found key:", key)

# Try to load the data - check if it's a file path or direct data
def load_stored_data(key_name):
    # Try to access from storage/variables
    data = None
    if key_name in locals():
        data = locals()[key_name]
    elif 'var_' + key_name in locals():
        data = locals()['var_' + key_name]

    # Check if it's a file path (string with .json or /)
    if isinstance(data, str) and ('.json' in data or ('/' in data and 'var_' not in data)):
        try:
            with open(data, 'r') as f:
                return json.load(f)
        except:
            pass

    # Otherwise, assume it's the data directly
    if isinstance(data, list):
        return data

    return []

# Load the data
cases = load_stored_data(case_result_key)
accounts = load_stored_data(account_result_key)

print("Cases loaded:", len(cases) if cases else 0)
print("Accounts loaded:", len(accounts) if accounts else 0)

if cases and accounts:
    # Create account to state mapping
    account_to_state = {}
    for acct in accounts:
        acct_id = acct.get('Id', '')
        if acct_id.startswith('#'):
            acct_id = acct_id[1:]
        account_to_state[acct_id] = acct.get('ShippingState')

    print("Account mapping size:", len(account_to_state))

    # Process cases to get state closure times
    state_durations = {}

    for case in cases:
        try:
            # Clean account ID
            acct_id = case.get('accountid', '')
            if acct_id and acct_id.startswith('#'):
                acct_id = acct_id[1:]

            # Get state
            state = account_to_state.get(acct_id)
            if not state:
                continue

            # Parse dates and calculate duration
            created_str = case.get('createddate', '').replace('+0000', '').replace('.000', '')
            closed_str = case.get('closeddate', '').replace('+0000', '').replace('.000', '')

            if 'T' in created_str and 'T' in closed_str:
                created = datetime.fromisoformat(created_str.replace('Z', '+00:00'))
                closed = datetime.fromisoformat(closed_str.replace('Z', '+00:00'))
                duration_hours = (closed - created).total_seconds() / 3600

                if state not in state_durations:
                    state_durations[state] = []
                state_durations[state].append(duration_hours)
        except Exception as e:
            continue

    print("States with data:", list(state_durations.keys()))

    # Calculate average closure time per state (need at least 3 cases)
    state_avg_duration = {}
    for state, durations in state_durations.items():
        if len(durations) >= 3:
            state_avg_duration[state] = sum(durations) / len(durations)

    print("States with enough data:", state_avg_duration)

    # Find state with quickest average closure
    if state_avg_duration:
        quickest_state = min(state_avg_duration.items(), key=lambda x: x[1])
        result = quickest_state[0]
        print("Quickest state:", result, "with avg hours:", quickest_state[1])
    else:
        result = "No sufficient data"
else:
    result = "Failed to load data"

print('___RESULT___:', result)

