        # Try to access the variable
        data = globals().get(key_str)
        if data is None:
            data = locals().get(key_str)
        return data
    except:
        return None

cases = get_stored_data(cases_key)
accounts = get_stored_data(accounts_key)

print("Raw cases:", type(cases))
print("Raw accounts:", type(accounts))

# If they are file paths, load them
if isinstance(cases, str) and ('/' in cases or '.json' in cases):
    with open(cases, 'r') as f:
        cases = json.load(f)

if isinstance(accounts, str) and ('/' in accounts or '.json' in accounts):
    with open(accounts, 'r') as f:
        accounts = json.load(f)

print("Final cases:", len(cases))
print("Final accounts:", len(accounts))

# Build account to state mapping
account_to_state = {}
for acct in accounts:
    acct_id = acct['Id']
    if acct_id.startswith('#'):
        acct_id = acct_id[1:]
    account_to_state[acct_id] = acct['ShippingState']

# Process cases by state
state_durations = {}
for case in cases:
    acct_id = case['accountid']
    if acct_id.startswith('#'):
        acct_id = acct_id[1:]

    state = account_to_state.get(acct_id)
    if not state:
        continue

    try:
        created = datetime.fromisoformat(case['createddate'].replace('.000+0000', '+00:00'))
        closed = datetime.fromisoformat(case['closeddate'].replace('.000+0000', '+00:00'))
        hours = (closed - created).total_seconds() / 3600

        if state not in state_durations:
            state_durations[state] = []
        state_durations[state].append(hours)
    except:
        continue

# Calculate averages (need minimum 3 cases per state)
avg_duration = {state: sum(times)/len(times) for state, times in state_durations.items() if len(times) >= 3}

# Get state with quickest average closure
if avg_duration:
    quickest = min(avg_duration.items(), key=lambda x: x[1])
    result = quickest[0]
else:
    result = "No data"

print("__RESULT__:")
print(json.dumps(result))

